import React from "react";
import { useParams, Link } from "react-router-dom";
import "./ServiceDetail.css";

const services = [
  {
    id: 1,
    category: "Travel & Stay",
    name: "Luxury Hotel Booking",
    image: "https://images.unsplash.com/photo-1560347876-aeef00ee58a1?fit=crop&w=1200&q=80",
    details:
      "Enjoy a world-class hotel experience with ocean views, private pools, and 24/7 concierge services. Perfect for family vacations and romantic getaways.",
  },
  {
    id: 2,
    category: "Beauty & Lifestyle",
    name: "Makeup & Hair Salon",
    image: "https://images.unsplash.com/photo-1508214751196-bcfd4ca60f91?fit=crop&w=1200&q=80",
    details:
      "Get premium beauty and hair styling from professionals near you. Ideal for weddings, travel, and events.",
  },
  {
    id: 3,
    category: "Transport",
    name: "Car & Bike Rentals",
    image: "https://images.unsplash.com/photo-1533473359331-0135ef1b58bf?fit=crop&w=1200&q=80",
    details:
      "Rent cars, SUVs, or bikes at affordable rates. Includes GPS, insurance, and flexible pick-up options.",
  },
  {
    id: 4,
    category: "Tours & Adventures",
    name: "Guided Tours",
    image: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=1200&q=80",
    details:
      "Join guided tours with local experts and discover hidden gems, cultural insights, and food experiences.",
  },
];

export default function ServiceDetail() {
  const { id } = useParams();
  const service = services.find((s) => s.id === Number(id));

  if (!service) {
    return <h2>Service not found</h2>;
  }

  return (
    <div className="service-detail-container">
      <img src={service.image} alt={service.name} className="service-detail-image" />
      <div className="service-detail-info">
        <h1>{service.name}</h1>
        <h4 className="service-category-tag">{service.category}</h4>
        <p>{service.details}</p>
        <Link to={`/booking/${service.id}`}>
          <button className="book-now-btn">Book Now</button>
        </Link>
      </div>
    </div>
  );
}
